diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 9a16ca96db76..b6859466aea1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -811,12 +811,13 @@ static Instruction *foldNoWrapAdd(BinaryOperator &Add,
   Value *Op0 = Add.getOperand(0), *Op1 = Add.getOperand(1);
   Type *Ty = Add.getType();
   Constant *Op1C;
+  Value *X;
+  Constant *NarrowC;
   if (!match(Op1, m_Constant(Op1C)))
     return nullptr;

   // Try this match first because it results in an add in the narrow type.
   // (zext (X +nuw C2)) + C1 --> zext (X + (C2 + trunc(C1)))
-  Value *X;
   const APInt *C1, *C2;
   if (match(Op1, m_APInt(C1)) &&
       match(Op0, m_OneUse(m_ZExt(m_NUWAddLike(m_Value(X), m_APInt(C2))))) &&
@@ -826,9 +827,9 @@ static Instruction *foldNoWrapAdd(BinaryOperator &Add,
     return new ZExtInst(Builder.CreateNUWAdd(X, NewC), Ty);
   }

+
   // More general combining of constants in the wide type.
   // (sext (X +nsw NarrowC)) + C --> (sext X) + (sext(NarrowC) + C)
-  Constant *NarrowC;
   if (match(Op0,
             m_OneUse(m_SExt(m_NSWAddLike(m_Value(X), m_Constant(NarrowC)))))) {
     Value *WideC = Builder.CreateSExt(NarrowC, Ty);
@@ -836,18 +837,19 @@ static Instruction *foldNoWrapAdd(BinaryOperator &Add,
     Value *WideX = Builder.CreateSExt(X, Ty);
     return BinaryOperator::CreateAdd(WideX, NewC);
   }
-  // (zext (X +nuw NarrowC)) + C --> (zext X) + (zext(NarrowC) + C)
-  if (match(Op0,
-            m_OneUse(m_ZExt(m_NUWAddLike(m_Value(X), m_Constant(NarrowC)))))) {
-    Value *WideC = Builder.CreateZExt(NarrowC, Ty);
+  // (zext nneg (X +nsw NarrowC)) + C --> (sext X) + (sext(NarrowC) + C)
+  // zext nneg is semantically equivalent to sext for non-negative values,
+  // so we can fold it similarly.
+  if (match(Op0, m_OneUse(m_NNegZExt(m_NSWAddLike(m_Value(X),
+                                                  m_Constant(NarrowC)))))) {
+    Value *WideC = Builder.CreateSExt(NarrowC, Ty);
     Value *NewC = Builder.CreateAdd(WideC, Op1C);
-    Value *WideX = Builder.CreateZExt(X, Ty);
+    Value *WideX = Builder.CreateSExt(X, Ty);
     return BinaryOperator::CreateAdd(WideX, NewC);
   }

   return nullptr;
 }
-
 Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   Value *Op0 = Add.getOperand(0), *Op1 = Add.getOperand(1);
   Type *Ty = Add.getType();

